            iterator_to_array($sections),
            iterator_to_array($footers)
        );

        // Process each element
        foreach ($elements as $element) {
            $src = $element->getAttribute('src');
            $dataSrc = $element->getAttribute('data-src');
            $dataBackground = $element->getAttribute('data-background');
            $srcset = $element->getAttribute('srcset');
            $style = $element->getAttribute('style');

            // Check various source attributes for WebP conversion
            $sources = array($src, $dataSrc, $dataBackground);
            foreach ($sources as $source) {
                check_image_file_for_webp_converter($source, $webp_on_page);
            }

            // Process srcset if present
            if ($srcset) {
                $srcsetArray = explode(',', $srcset);
                foreach ($srcsetArray as $srcsetItem) {
                    $srcsetItemArray = explode(' ', trim($srcsetItem));
                    check_image_file_for_webp_converter($srcsetItemArray[0], $webp_on_page);
                }
            }

            // Process inline style if present
            if ($style) {
                preg_match_all('/url\s*\(\s*[\'"]?([^\'")]+)[\'"]?\s*\)/i', $style, $matches);
                if (!empty($matches[1])) {
                    foreach ($matches[1] as $url) {
                        check_image_file_for_webp_converter($url, $webp_on_page);
                    }
                }
            }
        }

        // Process <style> tags
        foreach ($styles as $style) {
            preg_match_all('/url\s*\(\s*[\'"]?([^\'")]+)[\'"]?\s*\)/i', $style->nodeValue, $matches);
            if (!empty($matches[1])) {
                foreach ($matches[1] as $url) {
                    check_image_file_for_webp_converter($url, $webp_on_page);
                }
            }
        }

        // Add some additional replacements
        $webp_on_page['/webp/webp/'] = '/webp/';
        $webp_on_page['//webp/'] = '/webp/';
        $webp_on_page['.webp.webp'] = '.webp';

        // Apply replacements if any found
        if (count($webp_on_page))
            $output = str_replace(array_keys($webp_on_page), array_values($webp_on_page), $output);

        // Cache the results
        $modx->cacheManager->set($cache_key, serialize($webp_on_page), 0, $options);
    } else {
        // If cache exists, use it
        $webp_on_page = unserialize($cached_webp_on_page);
        if (count($webp_on_page)) {
            $output = str_replace(array_keys($webp_on_page), array_values($webp_on_page), $output);
        }
    }
    return '';
}

if ($modx->event->name == 'OnWebPagePrerender') {
    $output = &$modx->resource->_output;

    // Регулярное выражение для поиска всех script-тегов
    $pattern = '/<script\b([^>]*)>(.*?)<\/script>/is';

    // Собираем все скрипты
    preg_match_all($pattern, $output, $matches, PREG_SET_ORDER);

    $scripts = '';
    foreach ($matches as $match) {
        $full_match = $match[0];
        $attributes = $match[1];
        $content = $match[2];

        // Если уже есть defer/async/module - пропускаем
        if (preg_match('/\b(defer|async|type="module")\b/i', $attributes)) {
            continue;
        }

        // Добавляем defer
        $new_attributes = trim($attributes);
        if (!empty($new_attributes)) {
            $new_attributes .= ' ';
        }
        //$new_attributes .= 'defer';
        $new_attributes .= 'async';

        // Создаем новый тег script
        $new_script = "<script {$new_attributes}>{$content}</script>";

        // Удаляем оригинальный script из контента
        $output = str_replace($full_match, '', $output);

        // Добавляем в коллекцию для вставки перед </body>
        $scripts .= $new_script . "\n";
    }

    // Вставляем все скрипты перед </body>
    if (!empty($scripts)) {
        $output = preg_replace('/<\/body>/i', $scripts . '</body>', $output);
    }

     // Добавляем пассивные обработчики для scroll/click
    $output = preg_replace(
        '/addEventListener\((\'|")(scroll|click|touchstart|mousemove)\1(.*?)\)/i',
        'addEventListener($1$2$1, $3, {passive: true})',
        $output
    );

}

if ($modx->event->name == 'OnWebPagePrerender') {
    $output = &$modx->resource->_output;

    // 1. Перенос тяжелых операций в Web Workers
    $output = preg_replace_callback('/<script>([\s\S]*?heavy_operation[\s\S]*?)<\/script>/i', function($matches) {
        $jsCode = $matches[1];
        $workerHash = md5($jsCode);
        $workerFile = 'assets/js/workers/' . $workerHash . '.js';

        // Создаем файл воркера
        file_put_contents(MODX_BASE_PATH . $workerFile, $jsCode);

        // Заменяем оригинальный код на работу с воркером
        return <<<HTML
<script>
if (window.Worker) {
    const worker = new Worker('{$workerFile}');
    worker.onmessage = function(e) {
        console.log('Worker result:', e.data);
    };
    worker.postMessage('start');
} else {
    console.warn('Web Workers not supported');
    {$jsCode}
}
</script>
HTML;
    }, $output);

    // 2. Оптимизация обработчиков событий
    $output = preg_replace('/addEventListener\(([\'"])(click|scroll|mousemove)\1/g', 
        'addEventListener($1$2$1, {passive: true, capture: false}', 
        $output);

    // 3. Разделение длинных задач
    $output = str_replace('function longTask()', 'async function longTask()', $output);
    $output = preg_replace('/(\w+)\.forEach\(function\(([^)]+)\)\{/',
        'for (const $2 of $1) {', $output);

    // 4. Добавление requestIdleCallback для не критичных задач
    $output = preg_replace('/(setTimeout\(function\(\)\s*\{)([^}]+task[^}]+)\}/',
        'requestIdleCallback(() => {$2})', $output);
}

/**
 * Plugin: OptimizeThirdParty
 * Описание: Оптимизирует загрузку стороннего кода, перенося его в конец страницы или загружая асинхронно
 */

$event = $modx->event->name;

if ($event == 'OnWebPagePrerender') {
    $content = &$modx->resource->_output;

    // Список скриптов для переноса (регулярные выражения)
    $scriptsToMove = array(
        '/<script[^>]*(google-analytics\.com|googletagmanager\.com|yandex\.ru\/metrika|facebook\.net|connect\.facebook\.net|vk\.com|twitter\.com|widget\.instagram\.com|recaptcha\.net|disqus\.com)[^>]*><\/script>/i',
        // Добавьте другие сторонние скрипты по мере необходимости
    );

    // Список скриптов для загрузки с атрибутом async/defer
    $scriptsToAsync = array(
        '/<script[^>]*(platform\.twitter\.com|cdn\.widget\.instagram\.com)[^>]*><\/script>/i',
        // Добавьте другие скрипты, которые можно загружать асинхронно
    );

    $scriptsToMoveFound = array();
    $scriptsToAsyncFound = array();

    // Ищем скрипты для переноса
    foreach ($scriptsToMove as $pattern) {
        preg_match_all($pattern, $content, $matches);
        if (!empty($matches[0])) {
            $scriptsToMoveFound = array_merge($scriptsToMoveFound, $matches[0]);
            $content = preg_replace($pattern, '', $content);
        }
    }

    // Ищем скрипты для асинхронной загрузки
    foreach ($scriptsToAsync as $pattern) {
        preg_match_all($pattern, $content, $matches);
        if (!empty($matches[0])) {
            foreach ($matches[0] as $script) {
                // Добавляем атрибут async или defer
                $asyncScript = preg_replace('/<script/i', '<script async defer', $script);
                $scriptsToAsyncFound[] = $asyncScript;
                $content = str_replace($script, '', $content);
            }
        }
    }

    // Переносим скрипты перед закрывающим тегом </body>
    if (!empty($scriptsToMoveFound)) {
        $movedScripts = implode("\n", $scriptsToMoveFound);
        $content = str_replace('</body>', $movedScripts . "\n</body>", $content);
    }

    // Добавляем асинхронные скрипты перед закрывающим тегом </body>
    if (!empty($scriptsToAsyncFound)) {
        $asyncScripts = implode("\n", $scriptsToAsyncFound);
        $content = str_replace('</body>', $asyncScripts . "\n</body>", $content);
    }

    // Оптимизация iframe (например, для YouTube, Vimeo)
    $content = preg_replace_callback('/<iframe[^>]+src=("|\')([^"\']+)\1[^>]*>/i', function($matches) {
        $src = $matches[2];
        // Заменяем iframe на placeholder с lazy loading
        return '<div class="lazy-iframe" data-src="' . $src . '">'
             . '<button class="lazy-iframe-load-btn">Загрузить содержимое</button>'
             . '</div>';
    }, $content);
}

/**
 * Plugin: AsyncCSSLoader
 * Описание: Преобразует все CSS-ресурсы для асинхронной загрузки
 * Событие: OnWebPagePrerender
 */

$event = $modx->event->name;

if ($event == 'OnWebPagePrerender') {
    $content = &$modx->resource->_output;

    // 1. Встраиваем скрипт загрузчика CSS в head
    $loaderScript = <<<HTML
<script>
/*! loadCSS rel=preload polyfill. [c]2017 Filament Group, Inc. MIT License */
!function(e){"use strict";var t=function(t,n,o){function i(e){return d.body?e():void setTimeout(function(){i(e)})}var d=e.document,r=d.createElement("link"),a=n||d.getElementsByTagName("script")[0],s=d.styleSheets;return r.rel="stylesheet",r.href=t,r.media="only x",o&&(r.onload=o),i(function(){a.parentNode.insertBefore(r,a)}),r.onloadcssdefined=function(e){for(var t=0;t<s.length;t++)s[t].href&&s[t].href===r.href&&(e=!0);e?r.onload():setTimeout(function(){r.onloadcssdefined(e)})},r.onloadcssdefined(function(){r.media=o||"all"}),r}
/*! loadCSS & preloadCSS function */
window.loadCSS=t;window.preloadCSS=function(e,n,o){return t(e,n,o)};
</script>
HTML;

    $content = str_replace('</head>', $loaderScript."\n</head>", $content);

    // 2. Обрабатываем все внешние CSS-ссылки
    $content = preg_replace_callback(
        '/<link(?=[^>]*\brel\s*=\s*[\'"]stylesheet[\'"])[^>]*href\s*=\s*[\'"]([^\'"]+)[\'"][^>]*>/i',
        function($matches) {
            $cssUrl = $matches[1];

            // Пропускаем специфичные файлы (например, шрифты)
            if (preg_match('/\.(woff2?|ttf|eot|svg)$/i', $cssUrl)) {
                return $matches[0];
            }

            return '<link rel="preload" as="style" href="'.$cssUrl.'" onload="this.onload=null;this.rel=\'stylesheet\'">'
                 . '<noscript><link rel="stylesheet" href="'.$cssUrl.'"></noscript>';
        },
        $content
    );

    // 3. Обрабатываем встроенные стили (можно добавить критический CSS)
    $criticalCss = '<style>'
                 . '/* Basic critical CSS to avoid FOUC */'
                 . 'body{visibility:hidden;opacity:0;}.css-loaded body{visibility:visible;opacity:1;transition:opacity 0.3s;}'
                 . '</style>'
                 . '<script>document.addEventListener("DOMContentLoaded",function(){document.documentElement.className+=" css-loaded";});</script>';

    $content = str_replace('</head>', $criticalCss."\n</head>", $content);

    // 4. Оптимизация @import в CSS (если нужно)
    $content = preg_replace('/@import\s+url\([\'"]([^\'"]+)[\'"]\)\s*;/i', 
        '<link rel="preload" as="style" href="$1" onload="this.onload=null;this.rel=\'stylesheet\'">', 
        $content);
}

